<template>
  <div>
        <!-- 面包屑导航 -->
        <el-breadcrumb separator="/">
            <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
            <el-breadcrumb-item><a href="/">商品管理</a></el-breadcrumb-item>
            <el-breadcrumb-item>商品分类</el-breadcrumb-item>
        </el-breadcrumb>

        <!-- 卡片试图 -->
        <el-card>
            <!-- 按钮 -->
             <el-row>
                 <el-col>
                     <el-button type="primary" style="margin-bottom:20px;" @click="showAddCate">添加分类</el-button>
                 </el-col>
             </el-row>
             <!-- 表格 -->
             <tree-table :data="cateList" :columns="columns" :show-index="true" index-text="#" border :expand-type="false" :selection-type="false">
                 <!-- 是否有效 -->
                 <template slot="isok" slot-scope="scope">
                     <i class="el-icon-success" v-if="scope.row.cat_deleted===false" style="color:lightgreen"></i>
                     <i class="el-icon-error" v-else style="color:red"></i>
                 </template>
                 <!-- 排序 -->
                 <template slot="order" slot-scope="scope">
                    <el-tag size="mini" v-if="scope.row.cat_level===0">一级</el-tag>
                    <el-tag size="mini" type="success" v-else-if="scope.row.cat_level===1">二级</el-tag>
                    <el-tag size="mini" type="warning" v-else>三级</el-tag>
                 </template>
                 <template slot="opt" slot-scope="scope">
                    <el-button @click="bianji(scope.row.cat_id)" type="primary" icon="el-icon-edit" size="mini">编辑</el-button>
                    <el-button @click="removeUser(scope.row.cat_id)" type="danger" icon="el-icon-delete" size="mini">删除</el-button>
                 </template>
             </tree-table>

             <!-- 分页 -->
             <el-pagination
                @size-change="handleSizeChange"
                @current-change="handleCurrentChange"
                :current-page="queryInfo.pagenum"
                :page-sizes="[3,5,10,15]"
                :page-size="queryInfo.pagesize"
                layout="total, sizes, prev, pager, next, jumper"
                :total="total">
            </el-pagination>
            
        </el-card>

        <!-- 点击添加出现的对话框 -->
        <el-dialog
            @close="addCateDialogClose"
            title="提示"
            :visible.sync="addCateDialogVisible"
            width="30%">
            <el-form :model="addCateForm" :rules="addCateFormRules" ref="addCateFormRef" label-width="100px">
                <el-form-item label="分类名称" prop="cat_name">
                    <el-input v-model="addCateForm.cat_name"></el-input>
                </el-form-item>
                <el-form-item label="父级分类">
                    <!-- 级联选择器 options用来指定数据源-->
                    <el-cascader
                        expand-trigger="hover"
                        v-model="selectedKeys"
                        :options="ParentCateList"
                        :props="cascaderProps"
                        @change="parentCateChange">
                    </el-cascader>
                </el-form-item>
            </el-form>
            <span slot="footer" class="dialog-footer">
                <el-button @click="addCateDialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="addCate">确 定</el-button>
            </span>
        </el-dialog>

        <!-- 点击添加出现的对话框 -->
         <el-dialog
                title="修改用户"
                :visible.sync="editDialogVisible"
                width="50%" @close="editDialogClosed">
            <el-form :model="editForm" ref="editFormRef" label-width="70px">
                <el-form-item label="分类名称">
                    <el-input  v-model="editForm.cat_name"></el-input>
                </el-form-item>
            </el-form>
            <span slot="footer" class="dialog-footer">
                <el-button @click="editDialogVisible = false">取 消</el-button>
                <el-button type="primary" @click="editUserInfo">确 定</el-button>
            </span>
        </el-dialog>

       
        
  </div>
</template>

<script>
export default {
  name: '',
  data() { 
    return {
        cateList:[],   //商品分类列表
        queryInfo:{   //查询条件
            type:3,
            pagenum:1,
            pagesize:5
        },
        total:0,   //总数据条数
        columns:[   //table指定列定义
           {
               label:'分类名称',
               prop:'cat_name'
           },
           {
               label:'是否有效',
               type:'template',
               template:'isok'
           },
           {
               label:'排序',
               type:'template',
               template:'order'
           },
           {
               label:'排操作序',
               type:'template',
               template:'opt'
           }
        ],  
        addCateDialogVisible:false,
        addCateForm:{   //添加分类的数据对象 
            cat_name:'',  //父级分类的名称
            cat_pid:0,   //父级分类的id
            cat_level:0,   //父级分类的等级
        },  
        addCateFormRules:{
            cat_name:[  //将要添加的分类名称
                {
                   required:true,
                   message:'请输入分类名称',
                   trigger:'blur'
               }
            ],   
        },
        ParentCateList:[],   //父级分类的列表
        cascaderProps:{
            value:'cat_id',
            label:'cat_name',
            children:'children'
        },   //指定级联选择器的具体配置对象
        selectedKeys:[],//选中的父级分类的id数组
        editForm:{},//查询到的用户信息编辑对象
        editDialogVisible:false,  //编辑框显示隐藏
        
    }
  },
  props: {

  },
  components:{
  },
  mounted() {
    this.getCateList()

  },
  methods:{
    async getCateList(){
        const { data:res } = await this.$axios.get('categories',{ params:this.queryInfo })
        console.log(res)
        if(res.meta.status!==200){
            return this.$message.error('获取商品分类失败')
        }
        this.cateList=res.data.result
        // 总数据条数赋值
        this.total=res.data.total
    },
    handleSizeChange(newSize){
        this.queryInfo.pagesize=newSize
        this.getCateList()
    },
    handleCurrentChange(newPage){
        this.queryInfo.pagenum=newPage
        this.getCateList()
    },
    // 点击添加分类
    showAddCate(){
        this.getParentCateList()
        this.addCateDialogVisible=true
    },
    // 获取父级分类的数据列表
    async getParentCateList(){
        const { data:res } = await this.$axios.get('categories',{params:{type:2}})
        if(res.meta.status!==200){
            return this.$message.error('获取父级分类列表失败')
        }
        this.ParentCateList=res.data
    },
    // 选择项发生变化触发
    parentCateChange(){
        console.log(this.selectedKeys)
        // 如果selectedKeys数据中的length大于0,证明选中了父级分类，反之，就说明没有
        if(this.selectedKeys.length>0){
            this.addCateForm.cat_pid=this.selectedKeys[this.selectedKeys.length-1]
            this.addCateForm.cat_level=this.selectedKeys.length
            return
        }else{
            this.addCateForm.cat_pid=0
            this.addCateForm.cat_level=0
        }
    },
    // 点击添加分类的确定
     addCate(){
        this.$refs.addCateFormRef.validate(async valid=>{
            if(!valid) return 
            const { data:res }= await this.$axios.post('categories',this.addCateForm)
            if(res.meta.status!==201){
                return this.$message.error('添加分类失败')
            }
            this.$message.success('添加分类成功')
            this.getCateList()
            this.addCateDialogVisible=false
        })
        

    },
    // 对话框重置
    addCateDialogClose(){
       this.$refs.addCateFormRef.resetFields()
       this.addCateForm.cat_pid=0
       this.addCateForm.cat_level=0
       this.selectedKeys=[]
    },
    // 点击编辑
    async bianji(id){
        console.log(id)
        const { data:res } = await this.$axios.get('categories/'+id)
        console.log(res)
        if(res.meta.status!==200){
            return this.$message.error('获取信息失败')
        }
        //TODO
        this.editForm=res.data
        console.log(this.editForm)
        this.editDialogVisible=true
    },
    // 编辑框重置
    editDialogClosed(){
        this.$refs.editFormRef.resetFields()
    },
    // 点击编辑框确定
    editUserInfo(){
        this.$refs.editFormRef.validate( async valid=>{
            if(!valid) return 
            // 请求接口
            const { data:res }= await this.$axios.put('categories/'+this.editForm.cat_id,{
               cat_name:this.editForm.cat_name,
            })
            if(res.meta.status!==200){
                return this.$message.error('更新用户信息失败')
            }
            // 关闭对话框
            this.editDialogVisible=false
            // 刷新用户列表
            this.getCateList()
            this.$message.success('更新数据成功')
            
        })
    },
    // 点击删除
    async removeUser(id){
        console.log(id)
       //    先弹框确认是否删除
       const confrimReault = await this.$confirm('此操作将永久删除该用户, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).catch(err=>{
            return err
        })
        if(confrimReault!=="confirm"){
            return this.$message.info('已经取消删除了')
        }
        const {data:res} = await this.$axios.delete('categories/'+id)
        console.log(res)
        if(res.meta.status!==200){
           return this.$message.error('删除失败')
        }
        this.$message.success('删除成功')
        this.getCateList()
    },

  },
 }
</script>

<style scoped>
.el-card{
    margin-top:15px;
}
.el-pagination{
    margin-top:15px;
}
.el-cascader{
    width:100%;
}
.el-cascader-menu__list{
    height:200px !important
}
</style>