<template>
  <div>
    <!-- 面包屑导航 -->
    <el-breadcrumb separator="/">
      <el-breadcrumb-item :to="{ path: '/' }">首页</el-breadcrumb-item>
      <el-breadcrumb-item>
        <a href="/">商品管理</a>
      </el-breadcrumb-item>
      <el-breadcrumb-item>参数分类</el-breadcrumb-item>
    </el-breadcrumb>

    <!-- 卡片视图 -->
    <el-card>
      <!-- 头部警告 -->
      <el-alert :closable="false" show-icon title="注意：只允许为第三级分类设置相关参数！" type="warning"></el-alert>
      <!-- 选择商品分类 -->
      <el-row class="cat_opt">
        <el-col>
          <span>选择商品分类：</span>
          <!-- 级联选择框 -->
          <el-cascader
            expand-trigger="hover"
            v-model="selectCatKeys"
            :options="cartlist"
            :props=" cateProps"
            @change="handleChange"
          ></el-cascader>
        </el-col>
      </el-row>

      <el-tabs v-model="activeName" @tab-click="handleTabClick">
        <!-- 动态参数面板 -->
        <el-tab-pane label="动态参数" name="many">
          <el-button type="primary" size="mini" :disabled="isBtnDisabled" @click="addDialogVisible=true">添加参数</el-button>
          <!-- 动态参数表格 -->
          <el-table :data="mangTableData" style="width: 100%" border stripe>
            <!-- 展开行 -->
            <el-table-column type="expand">
                <template slot-scope="scope">
                    <!-- 循环渲染tag标签 -->
                    <el-tag @close="handleClose(i,scope.row)" class="tag" closable v-for="(item,i) in scope.row.attr_vals" :key="i">{{ item }}</el-tag>
                    <el-input
                        class="input-new-tag"
                        v-if="scope.row.inputVisible"
                        v-model="scope.row.inputValue"
                        ref="saveTagInput"
                        size="small"
                        @keyup.enter.native="handleInputConfirm(scope.row)"
                        @blur="handleInputConfirm(scope.row)"
                        >
                    </el-input>
                    <el-button v-else class="button-new-tag" size="small" @click="showInput(scope.row)">+ New Tag</el-button>
                </template>
            </el-table-column>
            <el-table-column type="index" label="#"></el-table-column>
            <el-table-column prop="attr_name" label="参数名称"></el-table-column>
            <el-table-column label="操作">
              <template slot-scope="scope">
                <el-button type="primary" icon="el-icon-edit" size="mini" @click="showeditDialog(scope.row.attr_id)">修改</el-button>
                <el-button type="danger" icon="el-icon-delete" size="mini" @click="removeParams(scope.row.attr_id)">删除</el-button>
              </template>
            </el-table-column>
          </el-table>
        </el-tab-pane>
        <!-- 静态属性面板 -->
        <el-tab-pane label="静态属性" name="only">
          <el-button type="primary" size="mini" :disabled="isBtnDisabled" @click="addDialogVisible=true">添加属性</el-button>
          <!-- 静态属性表格 -->
          <el-table :data="onlyTableData" style="width: 100%" border stripe>
               <!-- 展开行 -->
            <el-table-column type="expand">
                <template slot-scope="scope">
                    <!-- 循环渲染tag标签 -->
                    <el-tag @close="handleClose(i,scope.row)" class="tag" closable v-for="(item,i) in scope.row.attr_vals" :key="i">{{ item }}</el-tag>
                    <el-input
                        class="input-new-tag"
                        v-if="scope.row.inputVisible"
                        v-model="scope.row.inputValue"
                        ref="saveTagInput"
                        size="small"
                        @keyup.enter.native="handleInputConfirm(scope.row)"
                        @blur="handleInputConfirm(scope.row)"
                        >
                    </el-input>
                    <el-button v-else class="button-new-tag" size="small" @click="showInput(scope.row)">+ New Tag</el-button>
                </template>
            </el-table-column>
            <el-table-column type="index" label="#"></el-table-column>
            <el-table-column prop="attr_name" label="属性名称"></el-table-column>
            <el-table-column label="操作">
              <template slot-scope="scope">
                <el-button type="primary" icon="el-icon-edit" size="mini" @click="showeditDialog(scope.row.attr_id)">修改</el-button>
                <el-button type="danger" icon="el-icon-delete" size="mini" @click="removeParams(scope.row.attr_id)">删除</el-button>
              </template>
            </el-table-column>
          </el-table>
        </el-tab-pane>
      </el-tabs>
    </el-card>

    <!-- 添加对话框 -->
    <el-dialog
        :title="'添加'+titleText"
        :visible.sync="addDialogVisible"
        @close="addDialogClosed"
        width="50%"
        >
       <el-form :model="addForm" :rules="addFormRules" ref="addFormRef" label-width="100px">
            <el-form-item :label="titleText" prop="attr_name">
                <el-input v-model="addForm.attr_name"></el-input>
            </el-form-item>
        </el-form>
        <span slot="footer" class="dialog-footer">
            <el-button @click="addDialogVisible = false">取 消</el-button>
            <el-button type="primary" @click="addParams">确 定</el-button>
        </span>
    </el-dialog>
      
    <!-- 修改对话框 -->
     <el-dialog
        :title="'修改'+titleText"
        :visible.sync="editDialogVisible"
        @close="editDialogClosed"
        width="50%">
       <el-form :model="editForm" :rules="editFormRules" ref="editFormRef" label-width="100px">
            <el-form-item :label="titleText" prop="attr_name">
                <el-input v-model="editForm.attr_name"></el-input>
            </el-form-item>
        </el-form>
        <span slot="footer" class="dialog-footer">
            <el-button @click="editDialogVisible = false">取 消</el-button>
            <el-button type="primary" @click="editParams">确 定</el-button>
        </span>
    </el-dialog>


  </div>
</template>

<script>
export default {
  name: "",
  data() {
    return {
      cartlist: [],
      cateProps: {
        //级联选择框配置对象
        value: "cat_id",
        label: "cat_name",
        children: "children"
      },
      selectCatKeys: [], //级联选择框双向绑定到的数组
      activeName: "many", //被激活的页签名称
      mangTableData: [], //动态参数数据
      onlyTableData: [], //静态属性数据
      addDialogVisible:false,
      addForm:{
          attr_name:''
      },  //添加参数的表单数据对象
      addFormRules:{
          attr_name:[
              {
                  required:true,
                  message:'请输入参数名称',
                  trigger:'blur'
              }
          ]
      },//添加表单的验证规则对象
      editDialogVisible:false,
      editForm:{},  //修改的表单对象
      editFormRules:{    //修改表单数据对象

      },
    };
  },
  props: {},
  components: {},
  computed: {
    // 如果按钮需要被禁用，则返回true
    isBtnDisabled() {
      if (this.selectCatKeys.length !== 3) {
        return true;
      }
      return false;
    },
    // 当前选中的三级分类id
    cateId() {
      if (this.selectCatKeys.length === 3) {
        return this.selectCatKeys[2];
      }
      return null;
    },
    titleText(){
        if(this.activeName==="many"){
            return '动态参数'
        }
        return '静态属性'
    }
  },
  mounted() {
    //获取所有商品分类
    this.getCateList();
  },
  methods: {
    async getCateList() {
      const { data: res } = await this.$axios.get("categories");
      if (res.meta.status !== 200) {
        return this.$message.error("获取商品分类失败");
      }
      this.cartlist = res.data;
      console.log(this.cartlist);
    },
    // 级联选择框选中项变化会触发的方法
    handleChange() {
      this.getParamsDate();

    },
    // tab页签点击事件
    handleTabClick() {
      this.getParamsDate();
    },
    // 获取说有列表数据
    async getParamsDate() {
      // 证明选中的不是三级分类
      if (this.selectCatKeys.length !== 3) {
        this.selectCatKeys = [];
        this.mangTableData=[]
        this.onlyTableData=[]
        return;
      }
      // 根据所选分类id和当前所处面板获取对应参数
      const { data: res } = await this.$axios.get(
        `categories/${this.cateId}/attributes`,
        {
          params: { sel: this.activeName }
        }
      );
      if (res.meta.status !== 200) {
        return this.$message.error("获取参数失败");
      }
     
      res.data.forEach(item=>{
          item.attr_vals=item.attr_vals ? item.attr_vals.split(' '):[]
        //   控制文本框显示隐藏
        item.inputVisible=false
        item.inputValue=''
      })
       console.log(res.data);
      if (this.activeName === "many") {
        this.mangTableData = res.data;
        console.log(this.mangTableData);
      } else {
        this.onlyTableData = res.data;
      }
    },
    // 监听对话框的关闭事件
    addDialogClosed(){
        this.$refs.addFormRef.resetFields()   //TODO
    },
    // 点击按钮，添加参数
    addParams(){
        this.$refs.addFormRef.validate(async valid=>{
            if(!valid) return
            const { data:res} = await this.$http.post(`categories/${this.cateId}/attributes`,{
                attr_name:this.addForm.attr_name,
                attr_sel:this.activeName
            })
            if(res.meta.status!==201){
                return this.$message.error('添加参数失败')
            }
             this.$message.success('添加参数成功')
             this.addDialogVisible=false
             this.getParamsDate()
        })
    },
    // 点击确定按钮展示修改对话框
    async showeditDialog(attr_id){
        const { data:res } = await this.$axios.get(`categories/${this.cateId}/attributes/${attr_id}`,{
            params:{
                attr_sel:this.activeName
            }
        })
        if(res.meta.status!==200){
            return this.$message.error('获取参数信息失败')
        }
        this.editForm=res.data
        console.log(this.editForm)
        this.editDialogVisible=true
    },
    // 重置修改框
    editDialogClosed(){
        this.$refs.editFormRef.resetFields()
    },
    // 点击修改框的确定
    editParams(){
        this.$refs.editFormRef.validate(async valid=>{
            if(!valid) return 
            const { data:res } = await this.$axios.put(`categories/${this.cateId}/attributes/${this.editForm.attr_id}`,{
                attr_name:this.editForm.attr_name,
                attr_sel:this.activeName
            })
            if(res.meta.status!==200){
                return this.$message.error('修改参数失败')
            }
            this.$message.success('修改参数成功')
            this.getParamsDate()
            this.editDialogVisible=false
        })
    },
    // 点击删除
    async removeParams(attr_id){
        const confrimReault = await this.$confirm('此操作将永久删除该用户, 是否继续?', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        }).catch(err=>{
            return err
        })
        if(confrimReault!=="confirm"){
            return this.$message.info('已经取消删除了')
        }
        const {data:res} = await this.$axios.delete(`categories/${this.cateId}/attributes/${attr_id}`)
        console.log(res)
        if(res.meta.status!==200){
           return this.$message.error('删除失败')
        }
        this.$message.success('删除成功')
        this.getParamsDate()
    },
    // 文本框失去焦或按下回车键触发
    async handleInputConfirm(row){
         if(row.inputValue.trim().length===0){
             row.inputValue=''
            row.inputVisible=false
            return
        }
        // 如果没有return ,说明用户输入了真实数据
        row.attr_vals.push(row.inputValue.trim())
        row.inputValue=''
        row.inputVisible=false
         this.saveAttr(row)
        
         
    },
    async saveAttr(row){
        // 发起请求保存添加的操作
        const { data:res }= await this.$axios.put(`categories/${this.cateId}/attributes/${row.attr_id}`,{
            attr_name:row.attr_name,
            attr_sel:row.attr_sel,
            attr_vals:row.attr_vals.join(' ')
        })
        console.log(res)
        if(res.meta.status!==200){
            return this.$message.error('修改参数失败')
        }
        this.$message.success('修改成功')
    },
    // 点击按钮展示文本输入框
    showInput(row){
       row.inputVisible=true
    //    让文本框自动获取焦点
       this.$nextTick(_ => {
          this.$refs.saveTagInput.$refs.input.focus();
        });
    },
    handleClose(i,row){
        row.attr_vals.splice(i,1)
        this.saveAttr(row)
    }
    
  }
};
</script>

<style scoped>
.cat_opt {
  margin: 15px 0;
}
.tag{
   
    margin-top:10px;
}
.input-new-tag{
    width:120px;
}
</style>